insert into public.sign_compatibility (sign_a, sign_b, score, content) values
  ('aries', 'aries', 79, $j${"headline":"Dos Aries: mirándose en el mismo espejo","overview":"Cuando dos Aries se encuentran, hay un reconocimiento inmediato: el otro entiende sin que tengas que explicarte, porque comparte el impulso de empezar. Es una conexión cómoda y familiar, casi como mirarse al espejo. El reto es que ese espejo también os devuelve vuestros defectos amplificados, y a veces cuesta no chocar justo donde más os parecéis.","love":"En el amor os sentís en casa. Ambos amáis con pasión inmediata y sin rodeos, así que rara vez tenéis que fingir ser quien no sois. Esa sintonía es un regalo, pero ojo: si los dos esperáis que sea el otro quien dé el primer paso, podéis quedaros esperando. Turnaos en cuidar la chispa.","passion":"La atracción nace de la complicidad: deseáis lo mismo y de la misma forma. Hay entrega y entendimiento, aunque también el riesgo de caer en la rutina por exceso de confianza. Atrévete a sorprender; con otro Aries sabes mejor que nadie qué le enciende.","communication":"Os entendéis con medias palabras, pero compartís también su impaciencia, y eso puede convertir una charla en un pulso. Cuando los dos tiráis del mismo lado sois imparables; cuando os empeñáis en tener razón, nadie cede. Escuchar de verdad será vuestra asignatura.","strengths":"Entendimiento instantáneo, valores compartidos y su coraje por partida doble. Pocas parejas se sienten tan \"vistas\" desde el primer día.","challenges":"Amplificáis vuestros defectos y competís en lo que más os define. Sin espacio propio, la relación puede volverse demasiado intensa o demasiado plana.","advice":"Recordad que parecerse no es lo mismo que completarse. Cultivad pequeñas diferencias y daos aire: lo que os une ya lo tenéis ganado."}$j$::jsonb),
  ('aries', 'tauro', 59, $j${"headline":"Aries y Tauro: vecinos que aprenden a destiempo","overview":"Aries y Tauro sois vecinos en la rueda del zodiaco, y eso se nota: os atraéis por lo que no entendéis del otro. El impulso de empezar se cruza con la calma que construye, y mezcláis fuego y tierra, dos formas muy distintas de sentir. No es un flechazo evidente, sino una relación que crece a fuego lento, a base de aprender el ritmo ajeno.","love":"El amor aquí pide traducción. Aries ama con pasión inmediata y sin rodeos y Tauro, en cambio, despacio y con los cinco sentidos. Al principio podéis sentir que habláis idiomas distintos, pero si tenéis paciencia descubriréis que cada uno aporta justo lo que al otro le falta. La ternura se construye, no viene de fábrica.","passion":"La química tarda en arrancar, pero cuando lo hace tiene el morbo de lo prohibido y lo desconocido. Os intriga eso que el otro hace y vosotros nunca haríais. Mantened viva esa curiosidad: es vuestro mejor afrodisíaco.","communication":"Pensáis a velocidades distintas, y ahí están la gracia y el roce. Aries aporta su coraje y Tauro, su lealtad. Si lo tomáis como un intercambio en vez de como una corrección, cada conversación os hará más sabios.","strengths":"Os complementáis en lo cotidiano y os sacáis de vuestra zona de confort. Juntos sois más completos de lo que erais por separado.","challenges":"Los ritmos y las prioridades chocan. Si no traducís lo que necesitáis, su impaciencia y su terquedad pueden agrandar la distancia.","advice":"Tratad las diferencias como un mapa, no como un muro. Preguntad más y supondréis menos: ahí está vuestra magia."}$j$::jsonb),
  ('aries', 'geminis', 88, $j${"headline":"Aries y Géminis: cómplices con química fácil","overview":"Lo vuestro fluye casi sin esfuerzo. Aries y Géminis os lleváis como si fuerais amigos de toda la vida, porque vuestros elementos (fuego y aire) se alimentan. Hay risa, estímulo y unas ganas naturales de planear cosas juntos. Es una de esas conexiones que empiezan ligeras y, sin daros cuenta, se vuelven importantes.","love":"En el amor os hacéis la vida fácil. El impulso de empezar se lleva de maravilla con la curiosidad que conecta, y eso se traduce en una relación alegre, sin tantos dramas. Aries ama con pasión inmediata y sin rodeos y Géminis con juego mental y palabras: dos estilos que, lejos de chocar, se enriquecen.","passion":"La atracción es juguetona y cómplice. Os deseáis desde la confianza y la diversión, sin presiones. No es el incendio más intenso del zodiaco, pero sí uno de los más sostenibles: la chispa se reaviva con una conversación o una escapada improvisada.","communication":"Aquí está vuestro punto fuerte: os entendéis hablando. Aries pone su coraje, Géminis pone su ingenio, y juntos resolvéis casi todo charlando. Cuidad de no quedaros solo en la superficie ligera: también merecéis las conversaciones hondas.","strengths":"Amistad, humor y proyectos compartidos. Sois esa pareja que además es equipo, y eso se nota en lo bien que respiráis juntos.","challenges":"Tanta facilidad puede haceros evitar los temas incómodos. Si nunca os enfadáis, quizá es que no os estáis diciendo todo.","advice":"No deis por sentado lo fácil. Regad la complicidad con planes nuevos y con verdades dichas a tiempo: tenéis una base envidiable."}$j$::jsonb),
  ('aries', 'cancer', 45, $j${"headline":"Aries y Cáncer: chispas que encienden y queman","overview":"Aquí saltan chispas, para lo bueno y para lo difícil. Aries y Cáncer os atraéis con fuerza magnética, pero mezcláis fuego y agua, dos formas muy distintas de sentir de maneras que chocan. El impulso de empezar tensa con la ternura que protege: o aprendéis a usar esa fricción como motor, o acabáis agotándoos en el mismo punto una y otra vez.","love":"El amor entre vosotros es intenso y desafiante. Os deseáis precisamente por lo que os diferencia, pero ese mismo contraste enciende discusiones. Aries ama con pasión inmediata y sin rodeos; Cáncer, en cambio, con entrega y necesidad de nido. Funcionará si dejáis de querer cambiar al otro y empezáis a admirarlo.","passion":"En lo físico hay fuego del bueno: la tensión se traduce en una atracción casi adictiva. El problema llega cuando la pasión de la cama se cuela en las discusiones del salón. Canalizad esa electricidad antes de que os queme.","communication":"Es vuestro gran reto. Su impaciencia se enreda con su susceptibilidad y una conversación tonta puede escalar en segundos. Pero si aprendéis a parar a tiempo, su coraje y su capacidad de cuidar pueden convertir cada choque en un avance real.","strengths":"Os retáis, os despertáis y no os aburrís jamás. Si lo trabajáis, esta tensión os hace crecer más que cualquier relación cómoda.","challenges":"El orgullo, los reproches y la lucha por tener razón. Sin autocontrol, la atracción se convierte en desgaste.","advice":"Elegid las batallas y bajad las armas primero. Lo vuestro no es incompatible: es exigente. Y a veces lo exigente es justo lo que transforma."}$j$::jsonb),
  ('aries', 'leo', 94, $j${"headline":"Aries y Leo: almas en la misma frecuencia","overview":"Hay un entendimiento que reconocéis al instante: Aries y Leo compartís el elemento fuego, y eso crea una corriente cálida desde el primer minuto. No necesitáis explicaros; os captáis en ese lenguaje silencioso que pocos entienden. Donde otras parejas sudan, vosotros sentís que casi todo fluye solo.","love":"En el amor parecéis llevaros de toda la vida. El impulso de empezar y el corazón que brilla laten al mismo compás, y eso da una calma que reconforta de verdad. Aries ama con pasión inmediata y sin rodeos y Leo a lo grande, con gestos memorables, y en lugar de chocar, encajáis con una naturalidad que asusta.","passion":"La química surge sin forzarla. No es un incendio repentino, sino una hoguera constante que abriga. Os deseáis desde la confianza, así que la pasión prende más despacio pero dura muchísimo más. El cuerpo sigue, sin esfuerzo, lo que el corazón ya sabe.","communication":"Os entendéis casi sin palabras. Su coraje se suma a su generosidad y juntos tomáis decisiones con una fluidez envidiable. El único peligro es la pereza: tan a gusto estáis que podríais dejar de esforzaros. No deis por hecho lo que tenéis.","strengths":"Armonía, confianza y valores compartidos. Sois esa pareja que da paz, la que otros miran pensando \"así debería ser\".","challenges":"Tanta comodidad puede volverse acomodo. Sin metas nuevas, la relación corre el riesgo de apalancarse en lo conseguido.","advice":"Lo bueno también se riega. Poneos retos juntos y no confundáis calma con dejadez: tenéis un tesoro, cuidadlo."}$j$::jsonb),
  ('aries', 'virgo', 44, $j${"headline":"Aries y Virgo: atracción que pide ajuste constante","overview":"Aries y Virgo sois piezas de puzles distintos que, aun así, se buscan. El impulso de empezar y el detalle que cuida casi no tienen puntos en común, y mezcláis fuego y tierra, dos formas muy distintas de sentir. Os fascináis y os desconcertáis a partes iguales: lo vuestro funciona solo si aceptáis que tendréis que reajustaros una y otra vez.","love":"El amor aquí es un aprendizaje continuo. Justo cuando crees entender a Virgo, te sorprende; y a Virgo le pasa igual contigo. Aries ama con pasión inmediata y sin rodeos y Virgo en los pequeños gestos cotidianos: estilos tan diferentes que pedís un esfuerzo de traducción diario. Pero esa rareza también engancha.","passion":"La química es extraña y magnética: os atrae lo que no comprendéis del otro. Puede haber desencuentros en el deseo, momentos de \"no estamos sincronizados\". Hablarlo sin pudor es lo único que mantiene viva la llama.","communication":"Aquí está el trabajo. Pensáis y sentís de formas casi opuestas, así que los malentendidos son fáciles. Su impaciencia y su autocrítica no ayudan. Pero si os armáis de paciencia, su coraje y su dedicación construyen un puente que pocos saben tender.","strengths":"Os obligáis a creceros y a mirar el mundo con otros ojos. Nadie os enseñará tanto sobre vosotros mismos como el otro.","challenges":"La sensación de ir a destiempo y de no terminar de encajar. Sin aceptación, el cansancio puede más que la fascinación.","advice":"Dejad de intentar encajar a la fuerza. Aceptad la rareza como parte del encanto y negociad lo concreto: ahí ganáis."}$j$::jsonb),
  ('aries', 'libra', 75, $j${"headline":"Aries y Libra: polos opuestos que se imantan","overview":"Sois las dos caras de una misma moneda. Aries y Libra estáis enfrentados en la rueda del zodiaco, y por eso os atraéis como imanes: cada uno tiene justo lo que al otro le falta. El impulso de empezar frente a la armonía que equilibra. Juntos podéis formar un equilibrio perfecto… o un tira y afloja agotador.","love":"El amor entre opuestos es de los más intensos que existen. Os complementáis tan bien que parecéis encajar como piezas hechas la una para la otra. Aries ama con pasión inmediata y sin rodeos y Libra buscando belleza y equilibrio compartido: dos polos que, bien llevados, se equilibran y se calman mutuamente.","passion":"La atracción es pura electricidad: lo opuesto siempre seduce. En lo físico os buscáis con una intensidad magnética que cuesta explicar. Mientras mantengáis ese respeto por la diferencia, el deseo se renueva solo.","communication":"El reto es no tirar cada uno hacia su extremo. Su impaciencia y su indecisión pueden convertir lo complementario en una batalla de posturas. Pero si os escucháis, su coraje y su diplomacia se equilibran y os hacen, juntos, mucho más completos.","strengths":"Os completáis como nadie y os equilibráis en lo que cada uno exagera. La química es innegable y duradera si hay respeto.","challenges":"La tendencia a polarizar: cuanto más tira uno, más tira el otro. Sin punto medio, lo magnético se vuelve cansino.","advice":"Buscad el centro, no la victoria. Vuestra fuerza está en el equilibrio: lo que en el otro te irrita es, en el fondo, lo que viniste a aprender."}$j$::jsonb),
  ('aries', 'escorpio', 48, $j${"headline":"Aries y Escorpio: atracción que pide ajuste constante","overview":"Aries y Escorpio sois piezas de puzles distintos que, aun así, se buscan. El impulso de empezar y la intensidad que transforma casi no tienen puntos en común, y mezcláis fuego y agua, dos formas muy distintas de sentir. Os fascináis y os desconcertáis a partes iguales: lo vuestro funciona solo si aceptáis que tendréis que reajustaros una y otra vez.","love":"El amor aquí es un aprendizaje continuo. Justo cuando crees entender a Escorpio, te sorprende; y a Escorpio le pasa igual contigo. Aries ama con pasión inmediata y sin rodeos y Escorpio todo o nada, hasta el fondo: estilos tan diferentes que pedís un esfuerzo de traducción diario. Pero esa rareza también engancha.","passion":"La química es extraña y magnética: os atrae lo que no comprendéis del otro. Puede haber desencuentros en el deseo, momentos de \"no estamos sincronizados\". Hablarlo sin pudor es lo único que mantiene viva la llama.","communication":"Aquí está el trabajo. Pensáis y sentís de formas casi opuestas, así que los malentendidos son fáciles. Su impaciencia y sus celos no ayudan. Pero si os armáis de paciencia, su coraje y su entrega total construyen un puente que pocos saben tender.","strengths":"Os obligáis a creceros y a mirar el mundo con otros ojos. Nadie os enseñará tanto sobre vosotros mismos como el otro.","challenges":"La sensación de ir a destiempo y de no terminar de encajar. Sin aceptación, el cansancio puede más que la fascinación.","advice":"Dejad de intentar encajar a la fuerza. Aceptad la rareza como parte del encanto y negociad lo concreto: ahí ganáis."}$j$::jsonb),
